// graphIssueStableID returns a deterministic identifier for a docgraph issue,
// computed from its kind/path/id/relatedPath tuple. The same issue produced by
// two graph builds yields the same ID, which lets the UI pass it back to
// graphRepairIssue without needing the server to remember per-build state.
func graphIssueStableID(issue docgraph.GraphIssue) string {
	payload := strings.Join([]string{
		string(issue.Kind),
		issue.Path,
		issue.ID,
		issue.RelatedPath,
	}, "\x00")
	sum := sha1.Sum([]byte(payload))
	return hex.EncodeToString(sum[:])
}

// docToGQL converts a docgraph.Document to the GraphQL Document model.
func docToGQL(d docgraph.Document) *Document {
	doc := &Document{
		ID:         d.ID,
		Path:       d.Path,
		Title:      d.Title,
		DependsOn:  d.DependsOn,
		Inputs:     d.Inputs,
		Dependents: d.Dependents,
		ParkingLot: d.ParkingLot,
	}
	if doc.DependsOn == nil {
		doc.DependsOn = []string{}
	}
	if doc.Inputs == nil {
		doc.Inputs = []string{}
	}
	if doc.Dependents == nil {
		doc.Dependents = []string{}
	}
	if d.Prompt != "" {
		p := d.Prompt
		doc.Prompt = &p
	}
	if d.Review.ReviewedAt != "" || d.Review.SelfHash != "" {
		depsJSON, _ := json.Marshal(d.Review.Deps)
		doc.Review = &DocumentReview{
			SelfHash:   d.Review.SelfHash,
			Deps:       string(depsJSON),
			ReviewedAt: d.Review.ReviewedAt,
		}
	}
	if d.ExecDef != nil {
		active := d.ExecDef.Active
		required := d.ExecDef.Required
		graphSource := true
		doc.ExecDef = &DocumentExecDef{
			ArtifactIds: d.ExecDef.ArtifactIDs,
			Active:      &active,
			Required:    &required,
			GraphSource: &graphSource,
		}
	}
	return doc
}

